import importlib.util, sys, tokenize, io
sys.path.insert(0, '/tmp/eval_sqli')
src = open('/tmp/eval_sqli/app.py').read()
def analyze(s):
    try:
        toks = list(tokenize.generate_tokens(io.StringIO(s).readline))
    except Exception:
        return (False, False)
    has_concat = False; has_fstr = False; i = 0; n = len(toks)
    while i < n:
        t = toks[i]
        if t.type == tokenize.NAME and t.string == 'execute':
            j = i + 1
            while j < n and toks[j].type in (tokenize.COMMENT, tokenize.NL, tokenize.NEWLINE):
                j += 1
            if j < n and toks[j].type == tokenize.OP and toks[j].string == '(':
                depth = 0; k = j; strs = []; ops = []
                while k < n:
                    tk = toks[k]
                    if tk.type == tokenize.OP and tk.string == '(': depth += 1
                    elif tk.type == tokenize.OP and tk.string == ')':
                        depth -= 1
                        if depth == 0: break
                    elif tk.type == tokenize.STRING: strs.append(tk)
                    elif hasattr(tokenize, 'FSTRING_START') and tk.type == tokenize.FSTRING_START: strs.append(tk)
                    elif tk.type == tokenize.OP and tk.string == '+': ops.append(tk)
                    k += 1
                for st in strs:
                    pref = st.string.lstrip('rRbB')
                    if st.type != tokenize.STRING or pref[:1] in ('f', 'F'):
                        has_fstr = True
                if ops and strs:
                    has_concat = True
            i = j
        i += 1
    return (has_concat, has_fstr)
concat, fstr = analyze(src)
assert not concat, 'still builds a query with string concatenation inside execute()'
assert not fstr, 'still builds a query with an f-string inside execute()'
